    cx, cy = (W - 1) / 2.0, (H - 1) / 2.0

    best = None
    best_key = None
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
        if not valid(nx, ny):
            continue
        if resources:
            my_d = 10**9
            op_d = 10**9
            for tx, ty in resources:
                d1 = man(nx, ny, tx, ty)
                if d1 < my_d:
                    my_d = d1
                d2 = man(ox, oy, tx, ty)
                if d2 < op_d:
                    op_d = d2
            adv = op_d - my_d
        else:
            adv = man(nx, ny, ox, oy) * 0.01 - man(nx, ny, sx, sy) * 0.001
        center = abs(nx - cx) + abs(ny - cy)
        key = (adv, -center, dx, dy)
        if best_key is None or key > best_key:
            best_key = key
            best = [dx, dy]

    if best is None:
        for dx, dy in moves:
            nx, ny = sx + dx, sy + dy
            if valid(nx, ny):
                return [dx, dy]
        return [0, 0]
    return best
